  2	import { createWizardNodeState } from '@odf/core/components/utils';
  3	import {
  4	  diskModeDropdownItems,
  5	  MINIMUM_NODES,
  6	  NO_PROVISIONER,
  7	  arbiterText,
  8	  LSO_OPERATOR,
  9	  OCS_TOLERATION,
 10	  lsoInstallationPage,
 11	} from '@odf/core/constants';
 12	import { useNodesData, useLSODiskDiscovery } from '@odf/core/hooks';
 13	import { NodeData } from '@odf/core/types';
 14	import {
 15	  nodesWithoutTaints,
 16	  getLocalVolumeSetRequestData,
 17	} from '@odf/core/utils';
 18	import { getNamespace, LocalVolumeSetModel } from '@odf/shared';
 19	import { ErrorAlert } from '@odf/shared/generic/Error';
 20	import { LoadingInline } from '@odf/shared/generic/Loading';
 21	import { useFetchCsv } from '@odf/shared/hooks/use-fetch-csv';
 22	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 23	import { isCSVSucceeded } from '@odf/shared/utils';
 24	import { k8sCreate } from '@openshift-console/dynamic-plugin-sdk';
 25	import { TFunction } from 'react-i18next';
 26	import { Trans } from 'react-i18next';
 27	import { useNavigate } from 'react-router-dom-v5-compat';
 28	import { useWizardContext } from '@patternfly/react-core';
 29	import {
 30	  Alert,
 31	  AlertVariant,
 32	  Button,
 33	  Form,
 34	  Grid,
 35	  GridItem,
 36	  Modal,
 37	} from '@patternfly/react-core';
 38	import { ErrorHandler } from '../../error-handler';
 39	import { WizardDispatch, WizardNodeState, WizardState } from '../../reducer';
 40	import { LocalVolumeSetBody } from './body';
 41	import { SelectedCapacity } from './selected-capacity';
 42	import { useLSODiscoveredDisks } from './useLSODiscoveredDisks';
 43	import './create-local-volume-set-step.scss';
 44	
 45	const makeLocalVolumeSetCall = (
 46	  state: WizardState['createLocalVolumeSet'],
 47	  storageClassName: string,
 48	  setInProgress: React.Dispatch<React.SetStateAction<boolean>>,
 49	  setErrorMessage: React.Dispatch<React.SetStateAction<string>>,
 50	  ns: string,
 51	  onNext: () => void,
 52	  lvsNodes: WizardState['nodes'],
 53	  dispatch: WizardDispatch
 54	) => {
 55	  setInProgress(true);
 56	
 57	  const nodes = lvsNodes.map((node) => node.hostName);
 58	
 59	  const requestData = getLocalVolumeSetRequestData(
 60	    { ...state, storageClassName },
 61	    nodes,
 62	    ns,
 63	    OCS_TOLERATION
 64	  );
 65	  k8sCreate({ model: LocalVolumeSetModel, data: requestData })
 66	    .then(() => {
 67	      setInProgress(false);
 68	      if (!storageClassName) {
 69	        dispatch({
 70	          type: 'wizard/setStorageClass',
 71	          payload: { name: state.volumeSetName, provisioner: NO_PROVISIONER },
 72	        });
 73	      }
 74	      onNext();
 75	    })
 76	    .catch((err) => {
 77	      setErrorMessage(err.message);
 78	      setInProgress(false);
 79	    });
 80	};
 81	
 82	const ConfirmationModal: React.FC<ConfirmationModalProps> = ({
 83	  state,
 84	  dispatch,
 85	  setInProgress,
 86	  setErrorMessage,
 87	  storageClassName,
 88	  stepIdReached,
 89	  ns,
 90	  nodes,
 91	}) => {
 92	  const { t } = useCustomTranslation();
 93	  const { goToNextStep, activeStep } = useWizardContext();
 94	
 95	  const cancel = () => {
 96	    dispatch({
 97	      type: 'wizard/setCreateLocalVolumeSet',
 98	      payload: { field: 'showConfirmModal', value: false },
 99	    });
100	  };
101	
102	  const handleNext = () => {
103	    const stepId = activeStep.id as number;
104	    dispatch({
105	      type: 'wizard/setStepIdReached',
106	      payload: stepIdReached <= stepId ? stepId + 1 : stepIdReached,
107	    });
108	    goToNextStep();
109	  };
110	
111	  const makeLVSCall = () => {
112	    cancel();
113	    makeLocalVolumeSetCall(
114	      state,
115	      storageClassName,
116	      setInProgress,
117	      setErrorMessage,
118	      ns,
119	      handleNext,
120	      nodes,
121	      dispatch
122	    );
123	  };
124	
125	  const description = (
126	    <>
127	      <span>
128	        {t("After the LocalVolumeSet is created you won't be able to edit it.")}
129	      </span>
130	      <p className="pf-v6-u-pt-sm">
131	        <strong>{t('Note:')} </strong>
132	        {arbiterText(t)}
133	      </p>
134	    </>
135	  );
136	  return (
137	    <Modal
138	      title={t('Create LocalVolumeSet')}
139	      isOpen={state.showConfirmModal}
140	      onClose={cancel}
141	      variant="small"
142	      actions={[
143	        <Button key="confirm" variant="primary" onClick={makeLVSCall}>
144	          {t('Yes')}
145	        </Button>,
146	        <Button key="cancel" variant="link" onClick={cancel}>
147	          {t('Cancel')}
148	        </Button>,
149	      ]}
150	      description={description}
151	    >
152	      <p>{t('Are you sure you want to continue?')}</p>
153	    </Modal>
154	  );
155	};
156	
157	type ConfirmationModalProps = {
158	  state: WizardState['createLocalVolumeSet'];
159	  dispatch: WizardDispatch;
160	  storageClassName: string;
161	  ns: string;
162	  setInProgress: React.Dispatch<React.SetStateAction<boolean>>;
163	  setErrorMessage: React.Dispatch<React.SetStateAction<string>>;
164	  nodes: WizardState['nodes'];
165	  stepIdReached: WizardState['stepIdReached'];
166	};
167	
168	const RequestErrors: React.FC<RequestErrorsProps> = ({
169	  errorMessage,
170	  inProgress,
171	}) => (
172	  <>
173	    {errorMessage && <ErrorAlert message={errorMessage} />}
174	    {inProgress && <LoadingInline />}
175	  </>
176	);
177	
178	type RequestErrorsProps = { errorMessage: string; inProgress: boolean };
179	
180	export const LSOInstallAlert = () => {
181	  const { t } = useCustomTranslation();
182	  const navigate = useNavigate();
183	
184	  return (
185	    <Alert
186	      variant="info"
187	      title={t('Local Storage Operator not installed')}
188	      className="odf-create-lvs__alert--override"
189	      isInline
190	    >
191	      <Trans t={t as any} ns="plugin__odf-console">
192	        Before we can create a storage system, the Local Storage Operator needs
193	        to be installed. When installation is finished come back to Data
194	        Foundation to create a storage system.
195	        <div className="ceph-ocs-install__lso-alert__button">
196	          <Button
197	            type="button"
198	            variant="primary"
199	            onClick={() => navigate(lsoInstallationPage)}
200	          >
201	            Install
202	          </Button>
203	        </div>
204	      </Trans>
205	    </Alert>
206	  );
207	};
208	
209	const getLVSStepValidationErrors = (
210	  state: WizardState['createLocalVolumeSet'],
211	  t: TFunction
212	) => {
213	  const validationErrors: { title: string; description: string }[] = [];
214	  if (state.chartNodes.size < MINIMUM_NODES)
215	    validationErrors.push({
216	      title: t('Minimum Node Requirement'),
217	      description: t(
218	        'A minimum of 3 nodes are required for the initial deployment. Only {{nodes}} node match to the selected filters. Please adjust the filters to include more nodes.',
219	        { nodes: state.chartNodes.size }
220	      ),
221	    });
222	  if (!state.isValidDeviceType && state.deviceType.length !== 0)
223	    validationErrors.push({
224	      title: t('Cannot proceed with selected device types'),
225	      description: t(
226	        'Choose a different device type or combination, or select only mpath to proceed.'
227	      ),
228	    });
229	
230	  return validationErrors;
231	};
232	
233	export const CreateLocalVolumeSet: React.FC<CreateLocalVolumeSetProps> = ({
234	  state,
235	  storageClass,
236	  dispatch,
237	  nodes,
238	  stepIdReached,
239	  isMCG,
240	  systemNamespace,
241	}) => {
242	  const { t } = useCustomTranslation();
243	
244	  const [csv, csvLoaded, csvLoadError] = useFetchCsv({
245	    specName: LSO_OPERATOR,
246	  });
247	  const lsoNamespace = getNamespace(csv);
248	
249	  const [rawNodes, rawNodesLoaded, rawNodesLoadError]: [
250	    NodeData[],
251	    boolean,
252	    any,
253	  ] = useNodesData();
254	  const allNodes: WizardNodeState[] =
255	    createWizardNodeState(nodesWithoutTaints(rawNodes)) || [];
256	
257	  const [discoveryInProgress, discoveryError] = useLSODiskDiscovery(
258	    allNodes,
259	    lsoNamespace,
260	    !csvLoadError && csvLoaded
261	  );
262	
263	  const {
264	    filteredDisksOnSelectedNodes,
265	    allDiscoveredDisks,
266	    disksLoaded,
267	    disksError,
268	  } = useLSODiscoveredDisks(state, nodes, lsoNamespace, allNodes);
269	
270	  const [lvsInProgress, setLvsInProgress] = React.useState(false);
271	  const [lvsError, setLvsError] = React.useState(null);
272	
273	  const allLoaded =
274	    csvLoaded && !discoveryInProgress && rawNodesLoaded && disksLoaded;
275	
276	  const anyError =
277	    csvLoadError || rawNodesLoadError || discoveryError || disksError;
278	
279	  const lvsStepValidationErrors = getLVSStepValidationErrors(state, t);
280	
281	  return (
282	    <ErrorHandler
283	      loaded={allLoaded}
284	      loadingMessage={
285	        !csvLoaded
286	          ? t('Checking Local Storage Operator installation')
287	          : !allLoaded
288	            ? t('Discovering disks on all hosts. This may take a few minutes.')
289	            : null
290	      }
291	      error={anyError}
292	      errorMessage={
293	        csvLoadError || !isCSVSucceeded(csv) ? <LSOInstallAlert /> : null
294	      }
295	    >
296	      <>
297	        <Grid>
298	          <GridItem lg={8} md={8} sm={8}>
299	            <Form noValidate={false} className="odf-create-lvs__form">
300	              <LocalVolumeSetBody
301	                state={state}
302	                dispatch={dispatch}
303	                storageClassName={storageClass.name}
304	                allNodes={allNodes}
305	                nodes={nodes}
306	                defaultVolumeMode={
307	                  isMCG
308	                    ? diskModeDropdownItems.FILESYSTEM
309	                    : diskModeDropdownItems.BLOCK
310	                }
311	                systemNamespace={systemNamespace}
312	              />
313	            </Form>
314	          </GridItem>
315	          <GridItem
316	            lg={3}
317	            lgOffset={9}
318	            md={3}
319	            mdOffset={9}
320	            sm={3}
321	            smOffset={9}
322	            className="odf-create-lvs__donut-chart"
323	          >
324	            <SelectedCapacity
325	              dispatch={dispatch}
326	              state={state}
327	              chartDisks={filteredDisksOnSelectedNodes}
328	              allDiscoveredDisks={allDiscoveredDisks}
329	            />
330	          </GridItem>
331	        </Grid>
332	        <ConfirmationModal
333	          ns={lsoNamespace}
334	          nodes={nodes}
335	          state={state}
336	          dispatch={dispatch}
337	          setInProgress={setLvsInProgress}
338	          setErrorMessage={setLvsError}
339	          storageClassName={storageClass.name}
340	          stepIdReached={stepIdReached}
341	        />
342	        {!!lvsStepValidationErrors.length &&
343	          lvsStepValidationErrors.map((lvsStepValidationError) => (
344	            <Alert
345	              className="odf-create-lvs__alert"
346	              variant={AlertVariant.danger}
347	              title={lvsStepValidationError.title}
348	              isInline
349	            >
350	              {lvsStepValidationError.description}
351	            </Alert>
352	          ))}
353	        <RequestErrors errorMessage={lvsError} inProgress={lvsInProgress} />
354	      </>
355	    </ErrorHandler>
356	  );
357	};
358	
359	type CreateLocalVolumeSetProps = {
360	  state: WizardState['createLocalVolumeSet'];
361	  storageClass: WizardState['storageClass'];
362	  nodes: WizardState['nodes'];
363	  stepIdReached: WizardState['stepIdReached'];
364	  dispatch: WizardDispatch;
365	  isMCG: boolean;
366	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
367	};

